# -*- coding: utf-8 -*-
"""
ContactAuthor.py - Show author contact information

Display tutorial link, blog website and WeChat QR code.
"""
import os
import sys
import base64
import io

try:
    import rhinoscriptsyntax as rs
    import Rhino
    import Eto.Forms as forms
    import Eto.Drawing as drawing
    RHINO_ENV = True
except ImportError:
    RHINO_ENV = False


TUTORIAL_URL = "https://www.bilibili.com/video/BV1v5Z9BREUe?vd_source=f242198d6ed5525eaa203a01c38b985b"
BLOG_URL = "https://www.spancore.cn"
TUTORIAL_TITLE = "【效率起飞】SAP2000模型一键导入Rhino！"

# ============ 公众号二维码 base64 ============
# 使用方法：将你的二维码图片转为 base64 字符串替换下面的占位符
# 在 Python 中运行以下代码生成：
#   import base64
#   with open("qrcode_wechat.png", "rb") as f:
#       print(base64.b64encode(f.read()).decode())
# 然后把输出的字符串粘贴到下面替换 None
QRCODE_BASE64 = ""


class ContactDialog(forms.Dialog):
    def __init__(self):
        super().__init__()
        self.Title = "联系作者 - SpanCoreLink"
        self.Padding = drawing.Padding(20)
        self.Resizable = False
        self.MinimumSize = drawing.Size(480, 520)

        layout = forms.DynamicLayout()
        layout.DefaultSpacing = drawing.Size(5, 5)
        layout.Padding = drawing.Padding(10)

        # Title
        title_label = forms.Label()
        title_label.Text = "SpanCoreLink"
        title_label.Font = drawing.Font(title_label.Font.Family, 18, drawing.FontStyle.Bold)
        title_label.TextAlignment = forms.TextAlignment.Center
        layout.AddRow(title_label)

        subtitle_label = forms.Label()
        subtitle_label.Text = "SAP2000 与 Rhino 的桥梁"
        subtitle_label.TextAlignment = forms.TextAlignment.Center
        layout.AddRow(subtitle_label)

        layout.AddRow(None)  # spacer

        # Tutorial section
        tutorial_header = forms.Label()
        tutorial_header.Text = "📺 视频教程"
        tutorial_header.Font = drawing.Font(tutorial_header.Font.Family, 12, drawing.FontStyle.Bold)
        layout.AddRow(tutorial_header)

        tutorial_label = forms.Label()
        tutorial_label.Text = TUTORIAL_TITLE
        layout.AddRow(tutorial_label)

        tutorial_btn = forms.Button()
        tutorial_btn.Text = "打开B站教程"
        tutorial_btn.Click += self.on_open_tutorial
        layout.AddRow(tutorial_btn)

        layout.AddRow(None)  # spacer

        # Blog section
        blog_header = forms.Label()
        blog_header.Text = "🌐 博客网站"
        blog_header.Font = drawing.Font(blog_header.Font.Family, 12, drawing.FontStyle.Bold)
        layout.AddRow(blog_header)

        blog_label = forms.Label()
        blog_label.Text = BLOG_URL
        layout.AddRow(blog_label)

        blog_btn = forms.Button()
        blog_btn.Text = "打开博客网站"
        blog_btn.Click += self.on_open_blog
        layout.AddRow(blog_btn)

        layout.AddRow(None)  # spacer

        # QR code section
        qr_header = forms.Label()
        qr_header.Text = "📱 微信公众号"
        qr_header.Font = drawing.Font(qr_header.Font.Family, 12, drawing.FontStyle.Bold)
        layout.AddRow(qr_header)

        # 优先使用内嵌 base64，确保打包后也能显示
        if QRCODE_BASE64:
            from System import Array, Byte
            import System.IO
            qr_bytes = base64.b64decode(QRCODE_BASE64)
            net_bytes = Array[Byte](qr_bytes)
            ms = System.IO.MemoryStream(net_bytes)
            qr_image = drawing.Bitmap(ms)
            qr_view = forms.ImageView()
            qr_view.Image = qr_image
            qr_view.Size = drawing.Size(200, 200)
            layout.AddRow(qr_view)
        else:
            # 备用：尝试从文件加载
            qr_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), "icon", "qrcode_wechat.png")
            if os.path.exists(qr_path):
                qr_image = drawing.Bitmap(qr_path)
                qr_view = forms.ImageView()
                qr_view.Image = qr_image
                qr_view.Size = drawing.Size(200, 200)
                layout.AddRow(qr_view)
            else:
                qr_tip = forms.Label()
                qr_tip.Text = "（请设置 QRCODE_BASE64 或放置 icon/qrcode_wechat.png）"
                qr_tip.TextAlignment = forms.TextAlignment.Center
                layout.AddRow(qr_tip)

        layout.AddRow(None)  # spacer

        # Close button
        close_btn = forms.Button()
        close_btn.Text = "关闭"
        close_btn.Click += self.on_close
        layout.AddRow(close_btn)

        self.Content = layout

    def on_open_tutorial(self, sender, e):
        import webbrowser
        webbrowser.open(TUTORIAL_URL)

    def on_open_blog(self, sender, e):
        import webbrowser
        webbrowser.open(BLOG_URL)

    def on_close(self, sender, e):
        self.Close()


def contact_author():
    if not RHINO_ENV:
        print("This script must be run in Rhino.")
        return

    dialog = ContactDialog()
    dialog.ShowModal(Rhino.UI.RhinoEtoApp.MainWindow)


if __name__ == "__main__":
    contact_author()
